def reverse_words_preserve_spaces(text: str) -> str:
    if not text:
        return ""

    words = []
    whitespaces = []
    current_word = []
    current_whitespace = []

    for char in text:
        if char.isspace():
            if current_word:
                words.append("".join(current_word))
                current_word = []
            current_whitespace.append(char)
        else:
            if current_whitespace:
                whitespaces.append("".join(current_whitespace))
                current_whitespace = []
            current_word.append(char)

    if current_word:
        words.append("".join(current_word))
    if current_whitespace:
        whitespaces.append("".join(current_whitespace))

    # Handle cases where the string starts/ends with whitespace or words
    # The key is to correctly interleave reversed words and original whitespaces

    reversed_words = words[::-1]
    result_parts = []

    word_idx = 0
    whitespace_idx = 0

    # Determine if text starts with a word or whitespace
    starts_with_word = bool(words) and text.strip() and text.find(words[0]) == 0

    while word_idx < len(reversed_words) or whitespace_idx < len(whitespaces):
        if starts_with_word:
            if word_idx < len(reversed_words):
                result_parts.append(reversed_words[word_idx])
                word_idx += 1
            if whitespace_idx < len(whitespaces):
                result_parts.append(whitespaces[whitespace_idx])
                whitespace_idx += 1
        else: # Starts with whitespace
            if whitespace_idx < len(whitespaces):
                result_parts.append(whitespaces[whitespace_idx])
                whitespace_idx += 1
            if word_idx < len(reversed_words):
                result_parts.append(reversed_words[word_idx])
                word_idx += 1

    return "".join(result_parts)

def decode_run_length(encoded_string: str) -> str:
    decoded_parts = []
    current_number = []

    for char in encoded_string:
        if char.isdigit():
            current_number.append(char)
        else:
            if current_number:
                count = int("".join(current_number))
                decoded_parts.append(char * count)
                current_number = []
    return "".join(decoded_parts)

def decode_run_length(encoded_string: str) -> str:
    decoded_parts = []
    i = 0
    while i < len(encoded_string):
        count_str = ""
        while encoded_string[i].isdigit():
            count_str += encoded_string[i]
            i += 1
        count = int(count_str)
        char = encoded_string[i]
        decoded_parts.append(char * count)
        i += 1
    return "".join(decoded_parts)

