def reverse_words_preserve_spaces(text: str) -> str:
    if not text:
        return ""

    # Split the string into words and space sequences
    parts = []
    current_part = []
    is_in_word = False

    for char in text:
        if char.isspace():
            if is_in_word:
                parts.append("".join(current_part))
                current_part = []
                is_in_word = False
            current_part.append(char)
        else:
            if not is_in_word:
                if current_part:
                    parts.append("".join(current_part))
                    current_part = []
                is_in_word = True
            current_part.append(char)

    if current_part:
        parts.append("".join(current_part))

    words = []
    spaces = []

    for part in parts:
        if part and part[0].isspace():
            spaces.append(part)
        else:
            words.append(part)

    words.reverse()

    result_parts = []
    word_idx = 0
    space_idx = 0

    for part in parts:
        if part and part[0].isspace():
            result_parts.append(spaces[space_idx])
            space_idx += 1
        else:
            result_parts.append(words[word_idx])
            word_idx += 1

    return "".join(result_parts)

def rot13_cipher(text: str) -> str:
    result = []
    for char in text:
        if 'a' <= char <= 'z':
            rotated_char = chr(((ord(char) - ord('a') + 13) % 26) + ord('a'))
            result.append(rotated_char)
        elif 'A' <= char <= 'Z':
            rotated_char = chr(((ord(char) - ord('A') + 13) % 26) + ord('A'))
            result.append(rotated_char)
        else:
            result.append(char)
    return ''.join(result)

def reverse_words_and_case(text: str) -> str:
    if not text:
        return ""

    words = text.split(' ')
    reversed_words = []

    for word in words:
        reversed_words.append(word.swapcase())

    return ' '.join(reversed_words[::-1])

