def find_peak_elements(arr):
    if not arr:
        return []
    if len(arr) == 1:
        return [arr[0]]

    peaks = []
    n = len(arr)

    # Check first element
    if arr[0] > arr[1]:
        peaks.append(arr[0])

    # Check middle elements
    for i in range(1, n - 1):
        if arr[i] > arr[i-1] and arr[i] > arr[i+1]:
            peaks.append(arr[i])

    # Check last element
    if arr[n-1] > arr[n-2]:
        peaks.append(arr[n-1])

    return peaks

