def find_kth_smallest_in_merged_sorted_lists(list1: list[int], list2: list[int], k: int) -> int:
    p1, p2 = 0, 0
    current_val = 0

    while k > 0:
        if p1 < len(list1) and (p2 >= len(list2) or list1[p1] <= list2[p2]):
            current_val = list1[p1]
            p1 += 1
        elif p2 < len(list2) and (p1 >= len(list1) or list2[p2] < list1[p1]):
            current_val = list2[p2]
            p2 += 1
        k -= 1
    return current_val

