def count_common_elements(list_of_dictionaries: list[dict[str, list[str]]]) -> dict[str, int]:
    all_elements_counts = {}
    all_lists = []

    # Collect all lists and count individual element occurrences
    for d in list_of_dictionaries:
        for key in d:
            current_list = d[key]
            all_lists.append(current_list)
            for item in current_list:
                all_elements_counts[item] = all_elements_counts.get(item, 0) + 1

    # Determine which elements are common (appear in at least two different lists)
    element_to_list_set = {}
    for i, current_list in enumerate(all_lists):
        for item in set(current_list): # Use set to count unique occurrences within a single list
            if item not in element_to_list_set:
                element_to_list_set[item] = set()
            element_to_list_set[item].add(i)

    common_elements_result = {}
    for element, list_indices in element_to_list_set.items():
        if len(list_indices) >= 2:
            common_elements_result[element] = all_elements_counts[element]

    return common_elements_result

def count_word_frequencies(text: str) -> dict[str, int]:
    word_counts = {}
    punctuation = ".!,?;:"

    # Remove punctuation and split into words
    for p in punctuation:
        text = text.replace(p, "")

    words = text.lower().split()

    for word in words:
        word_counts[word] = word_counts.get(word, 0) + 1

    return word_counts

