import re

def count_word_frequencies(text_corpus: list[str]) -> dict[str, int]:
    word_counts = {}
    for document in text_corpus:
        # Normalize hyphens: replace 'a-b' with 'a b', remove other hyphens
        processed_doc = re.sub(r'([a-zA-Z])-(?=[a-zA-Z])', r'\1 ', document)
        processed_doc = re.sub(r'-', '', processed_doc)

        # Remove punctuation except spaces and letters/numbers
        # Then split by whitespace
        words = re.findall(r'\b[a-zA-Z0-9]+\b', processed_doc.lower())
        for word in words:
            word_counts[word] = word_counts.get(word, 0) + 1
    return word_counts

