        return 1

    total_sum = 0
    for i in range(1, int(n**0.5) + 1):
        if n % i == 0:
            total_sum += i
            if i * i != n:
                total_sum += n // i
    return total_sum

def is_prime(n: int) -> bool:
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

