def find_median_sorted_arrays(nums1: list[int], nums2: list[int]) -> float:
    """
    Given two sorted arrays nums1 and nums2 of size m and n respectively,
    return the median of the two sorted arrays.

    The overall run time complexity should be O(log(m+n)).

    You may assume nums1 and nums2 are both non-empty and do not contain duplicate elements.
    They are sorted in ascending order.

    Examples:
    find_median_sorted_arrays([1, 3], [2]) == 2.0
    find_median_sorted_arrays([1, 2], [3, 4]) == 2.5
    find_median_sorted_arrays([0, 0], [0, 0]) == 0.0
    """
    m, n = len(nums1), len(nums2)
    if m > n:
        nums1, nums2, m, n = nums2, nums1, n, m # Ensure nums1 is the shorter array

    low, high = 0, m
    half_len = (m + n + 1) // 2

    while low <= high:
        i = (low + high) // 2 # Partition point for nums1
        j = half_len - i    # Partition point for nums2

        if i < m and nums2[j-1] > nums1[i]:
            # i is too small, need to increase i
            low = i + 1
        elif i > 0 and nums1[i-1] > nums2[j]:
            # i is too big, need to decrease i
            high = i - 1
        else:
            # i is perfect
            max_left = 0
            if i == 0:
                max_left = nums2[j-1]
            elif j == 0:
                max_left = nums1[i-1]
            else:
                max_left = max(nums1[i-1], nums2[j-1])

            if (m + n) % 2 == 1:
                return float(max_left)

            min_right = 0
            if i == m:
                min_right = nums2[j]
            elif j == n:
                min_right = nums1[i]
            else:
                min_right = min(nums1[i], nums2[j])

            return (max_left + min_right) / 2.0

