def parse_key_value_string(data_string: str) -> dict:
    """
    Parses a string containing key-value pairs separated by semicolons, 
    where each key and value are separated by an equals sign.

    Keys and values can contain spaces. Leading/trailing whitespace around 
    keys and values should be stripped. Empty keys or values after stripping 
    should be ignored. If a key appears multiple times, the last occurrence's 
    value should be used.

    The input string might be empty or contain malformed pairs.
    Malformed pairs (e.g., 'key_only', '=value_only', 'key=') should be ignored.

    Args:
        data_string: A string like 'key1=value1; key2 = value2;key3=value3'

    Returns:
        A dictionary mapping parsed keys to their corresponding values.
        Returns an empty dictionary if the input string is empty or contains 
        no valid pairs.

    Examples:
        parse_key_value_string('name=Alice;age=30') == {'name': 'Alice', 'age': '30'}
        parse_key_value_string('  color=  blue ; size = M  ') == {'color': 'blue', 'size': 'M'}
        parse_key_string('empty=;key=value;malformed') == {'key': 'value'}
        parse_key_value_string('a=1;b=2;a=3') == {'a': '3', 'b': '2'}
        parse_key_value_string('') == {}
        parse_key_value_string('no_equals; another =') == {}
    """
    result = {}
    if not data_string:
        return result

    pairs = data_string.split(';')

    for pair in pairs:
        if '=' in pair:
            parts = pair.split('=', 1)
            key = parts[0].strip()
            value = parts[1].strip()

            if key and value:
                result[key] = value
    return result

