    # Create a new matrix to store the rotated result
    rotated_matrix = [[0] * n for _ in range(n)]

    for i in range(n):
        for j in range(n):
            # New row index is old column index
            # New column index is (n - 1 - old row index)
            rotated_matrix[j][n - 1 - i] = matrix[i][j]
    return rotated_matrix

def rotate_matrix_90_clockwise(matrix):
    n = len(matrix)
    if n == 0:
        return []

    # Transpose the matrix
    transposed = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            transposed[j][i] = matrix[i][j]

    # Reverse each row of the transposed matrix
    rotated = []
    for row in transposed:
        rotated.append(row[::-1])

    return rotated

def rotate_matrix_clockwise(matrix):
    n = len(matrix)
    if n == 0:
        return []

    # Create a new matrix for the rotated result
    rotated_matrix = [[0 for _ in range(n)] for _ in range(n)]

    for r in range(n):
        for c in range(n):
            # The element at (r, c) in the original matrix
            # moves to (c, n - 1 - r) in the rotated matrix.
            rotated_matrix[c][n - 1 - r] = matrix[r][c]

    return rotated_matrix

def rotate_matrix_90_degrees_clockwise(matrix):
    n = len(matrix)
    if n == 0 or n == 1:
        return

    # Transpose the matrix
    for i in range(n):
        for j in range(i, n):
            matrix[i][j], matrix[j][i] = matrix[j][i], matrix[i][j]

    # Reverse each row
    for i in range(n):
        matrix[i].reverse()

