def rotate_matrix_90_clockwise(matrix):
    n = len(matrix)
    if n == 0:
        return

    # Transpose the matrix
    for i in range(n):
        for j in range(i + 1, n):
            matrix[i][j], matrix[j][i] = matrix[j][i], matrix[i][j]

    # Reverse each row
    for i in range(n):
        matrix[i].reverse()

def merge_overlapping_intervals(intervals):
    if not intervals:
        return []

    # Sort intervals by their start times
    intervals.sort(key=lambda x: x[0])

    merged = []
    for interval in intervals:
        # If the merged list is empty or the current interval does not overlap
        # with the last merged interval, simply add it.
        if not merged or interval[0] > merged[-1][1]:
            merged.append(interval)
        # Otherwise, there is an overlap, so merge the current and previous
        # intervals by updating the end of the last merged interval.
        else:
            merged[-1][1] = max(merged[-1][1], interval[1])

    return merged

