def min_cost_climbing_stairs(cost: list[int]) -> int:
    n = len(cost)

    if n == 2:
        return min(cost[0], cost[1])

    # dp[i] will store the minimum cost to reach step i
    dp = [0] * n

    # Base cases
    dp[0] = cost[0]
    dp[1] = cost[1]

    for i in range(2, n):
        dp[i] = cost[i] + min(dp[i-1], dp[i-2])

    # The top of the floor is effectively one step beyond the last step of the cost array.
    # We can reach the top from either the last step (n-1) or the second to last step (n-2).
    # The cost of reaching the top from dp[n-1] is dp[n-1] (since we've already paid cost[n-1])
    # The cost of reaching the top from dp[n-2] is dp[n-2] (since we've already paid cost[n-2])
    return min(dp[n-1], dp[n-2])

def min_cost_climbing_stairs(cost: list[int]) -> int:
    n = len(cost)
    if n == 0:
        return 0
    if n == 1:
        return cost[0]

    dp = [0] * n

    # Base cases
    dp[0] = cost[0]
    dp[1] = cost[1]

    for i in range(2, n):
        dp[i] = cost[i] + min(dp[i-1], dp[i-2])

    # The top of the floor can be reached from step n-1 or step n-2.
    # We don't pay for the 'top' itself, only to reach it.
    return min(dp[n-1], dp[n-2])
